import React from 'react';
import { Link } from 'react-router-dom';
import './EventCard.css';

function EventCard({ event }) {
  const isSoldOut = event.seatsLeft === 0;
  const isLow = event.seatsLeft <= 20 && event.seatsLeft > 0;

  const formattedDate = new Date(event.date).toLocaleDateString('en-IN', {
    day: 'numeric',
    month: 'short',
    year: 'numeric',
  });

  return (
    <div className="event-card card">
      <div className="event-card__image-wrap">
        <img src={event.image} alt={event.title} className="event-card__image" loading="lazy" />
        <span className="badge badge-gold event-card__category">{event.category}</span>
        {isSoldOut && <div className="event-card__sold-out">SOLD OUT</div>}
      </div>

      <div className="event-card__body">
        <h3 className="event-card__title">{event.title}</h3>

        <div className="event-card__meta">
          <span>📅 {formattedDate} · {event.time}</span>
          <span>📍 {event.location}</span>
        </div>

        <div className="event-card__footer">
          <div className="event-card__price">
            <span className="event-card__price-label">From</span>
            <span className="event-card__price-value">₹{event.price.toLocaleString('en-IN')}</span>
          </div>

          <div className="event-card__seats">
            {isLow && <span className="badge badge-red">Only {event.seatsLeft} left</span>}
            {!isLow && !isSoldOut && <span className="badge badge-green">{event.seatsLeft} seats</span>}
          </div>
        </div>

        <div className="event-card__actions">
          <Link to={`/events/${event.id}`} className="btn-outline" style={{ flex: 1, textAlign: 'center' }}>
            View Details
          </Link>
          {!isSoldOut && (
            <Link to={`/booking/${event.id}`} className="btn-primary" style={{ flex: 1, textAlign: 'center' }}>
              Book Now
            </Link>
          )}
        </div>
      </div>
    </div>
  );
}

export default EventCard;
